<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        A2[&quot;节点 A&quot;] --&gt; S1[&quot;超级节点&lt;br/&gt;(B, C 环路)&quot;]</span></span>
